"""Starlette response classes."""
from __future__ import annotations

import http.cookies
import json
from typing import Any, Dict, Iterable, Iterator, Mapping, Optional, Tuple, Union

from starlette.types import Receive, Scope, Send


class Response:
    """
    Base ASGI response class.

    Usage::

        response = Response("Hello", media_type="text/plain")
        await response(scope, receive, send)
    """

    media_type: Optional[str] = None
    charset: str = "utf-8"
    status_code: int = 200

    def __init__(
        self,
        content: Any = None,
        status_code: int = 200,
        headers: Optional[Mapping[str, str]] = None,
        media_type: Optional[str] = None,
        background: Optional[Any] = None,
    ) -> None:
        self.status_code = status_code
        self.background = background
        self.body = self.render(content)
        self.headers = {**(headers or {})}
        if media_type:
            self.media_type = media_type

    def render(self, content: Any) -> bytes:
        if content is None:
            return b""
        if isinstance(content, bytes):
            return content
        return str(content).encode(self.charset)

    async def __call__(self, scope: Scope, receive: Receive, send: Send) -> None:
        await send({
            "type": "http.response.start",
            "status": self.status_code,
            "headers": [(k.lower().encode(), v.encode()) for k, v in self.headers.items()],
        })
        await send({"type": "http.response.body", "body": self.body})
        if self.background is not None:
            await self.background()


class JSONResponse(Response):
    """
    JSON response — serializes content to JSON.

    Usage::

        return JSONResponse({"users": []}, status_code=200)
    """

    media_type = "application/json"

    def render(self, content: Any) -> bytes:
        return json.dumps(
            content,
            ensure_ascii=False,
            allow_nan=False,
            indent=None,
            separators=(",", ":"),
        ).encode("utf-8")


class HTMLResponse(Response):
    """HTML response."""

    media_type = "text/html"


class PlainTextResponse(Response):
    """Plain text response."""

    media_type = "text/plain"


class RedirectResponse(Response):
    """
    HTTP redirect response.

    Usage::

        return RedirectResponse(url="/new-url", status_code=307)
    """

    def __init__(
        self,
        url: str,
        status_code: int = 307,
        headers: Optional[Mapping[str, str]] = None,
        background: Optional[Any] = None,
    ) -> None:
        super().__init__(content=b"", status_code=status_code, headers=headers, background=background)
        self.headers["location"] = url


class StreamingResponse(Response):
    """
    Streaming response — sends content in chunks.

    Usage::

        def generate():
            yield b"chunk 1"
            yield b"chunk 2"

        return StreamingResponse(generate(), media_type="text/plain")
    """

    def __init__(
        self,
        content: Union[Iterable[bytes], Any],
        status_code: int = 200,
        headers: Optional[Mapping[str, str]] = None,
        media_type: Optional[str] = None,
        background: Optional[Any] = None,
    ) -> None:
        self.body_iterator = content
        self.status_code = status_code
        self.headers = dict(headers or {})
        if media_type:
            self.media_type = media_type
        self.background = background

    async def __call__(self, scope: Scope, receive: Receive, send: Send) -> None:
        await send({
            "type": "http.response.start",
            "status": self.status_code,
            "headers": [(k.lower().encode(), v.encode()) for k, v in self.headers.items()],
        })
        async for chunk in self.body_iterator:
            await send({"type": "http.response.body", "body": chunk, "more_body": True})
        await send({"type": "http.response.body", "body": b""})
